values
('73054b03-f6eb-4f84-940d-29b65751afd5'::uuid, 'Angebot senden', 'angebot', 'Ihr Angebot für {{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>vielen Dank für Ihre Anfrage. Anbei erhalten Sie unser Angebot Nr. {{Offer.number}} für das Projekt {{Project.address}}.</p><p>Für Rückfragen stehen wir Ihnen gerne zur Verfügung.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 10, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), 'angebote', null, null, 'senden', 'dokument', false),
('60db266a-7034-43ec-bf77-24bfa2d4fa8d'::uuid, 'Angebot Nachtrag senden', 'angebot', 'Nachtrag zum Angebot für {{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>zu Ihrem Projekt {{Project.address}} übersenden wir Ihnen anbei einen Nachtrag zu unserem Angebot {{Offer.number}}.</p><p>Bei Fragen melden Sie sich jederzeit gerne.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 20, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), 'angebote', null, null, 'senden', 'dokument', false),
('582433b9-1096-4f5b-92c2-c47ce8146c98'::uuid, 'Auftrag bestätigen', 'auftrag', 'Auftragsbestätigung für {{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>vielen Dank für Ihren Auftrag. Hiermit bestätigen wir den Auftrag Nr. {{Order.number}} für das Projekt {{Project.address}}.</p><p>Wir freuen uns auf die Zusammenarbeit und melden uns zur Terminabstimmung.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 30, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), 'auftraege', null, null, 'bestaetigen', 'dokument', false),
('a6438111-1896-4035-af0a-8f4d3bbafcb4'::uuid, 'Rechnung senden', 'rechnung', 'Ihre Rechnung für {{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>anbei erhalten Sie unsere Rechnung Nr. {{Invoice.number}} über {{Invoice.amount}} für das Projekt {{Project.address}}.</p><p>Wir bitten um Begleichung bis zum {{Invoice.due_date}}.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 40, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), 'rechnungen', null, null, 'senden', 'dokument', false),
('d27de634-15f4-4013-91d6-4036d3fed2d3'::uuid, 'Zahlungserinnerung', 'mahnung', 'Zahlungserinnerung – Rechnung {{Invoice.number}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>sicher ist es Ihrer Aufmerksamkeit entgangen: Unsere Rechnung Nr. {{Invoice.number}} über {{Invoice.amount}} (fällig am {{Invoice.due_date}}) ist noch offen.</p><p>Wir bitten Sie höflich um Begleichung. Sollte sich Ihre Zahlung überschnitten haben, betrachten Sie dieses Schreiben als gegenstandslos.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 50, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), 'rechnungen', null, null, 'zahlungserinnerung', 'dokument', false),
('fda0f21e-1b19-4104-8231-9ebf6e4080bf'::uuid, 'Letzte Mahnung', 'mahnung', 'Letzte Mahnung – Rechnung {{Invoice.number}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>trotz unserer Erinnerung ist die Rechnung Nr. {{Invoice.number}} über {{Invoice.amount}} weiterhin offen.</p><p>Wir setzen Ihnen eine letzte Frist zur Zahlung. Nach Verstreichen behalten wir uns weitere Schritte vor.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 60, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), 'rechnungen', null, null, 'zahlungserinnerung', 'dokument', false),
('3417327f-1bce-4c7c-857c-bd151510de06'::uuid, 'Allgemeine Mail an Kunden', 'kunde', '{{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p></p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 100, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), null, null, null, null, 'projekt', false),
('e7918b0b-00e0-4541-bab6-c3858b56eab9'::uuid, 'Planstand senden', 'dokument', 'Aktueller Planstand – Projekt {{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>anbei übersenden wir Ihnen den aktuellen Planstand zum Projekt {{Project.address}} ({{Project.display_id}}).</p><p>Für Rückfragen stehen wir gerne zur Verfügung.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 70, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), null, null, null, 'senden', 'dokument', false),
('37d8355d-0478-47c7-8fde-b2fe8b7953f6'::uuid, 'Vor-Ort-Termin bestätigen', 'termin', 'Vor-Ort-Termin – {{Project.address}}', '<p>{{Customer.salutation}} {{Customer.name}},</p><p>hiermit bestätigen wir gerne unseren Vor-Ort-Termin zum Projekt {{Project.address}}.</p><p>Sollte etwas dazwischenkommen, geben Sie uns bitte rechtzeitig Bescheid.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 80, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), null, null, null, 'termin_bestaetigen', 'termin', false),
('db623317-d75a-42ca-9b5c-39b060425621'::uuid, 'Subunternehmer anfragen', 'subunternehmer', 'Anfrage zu Projekt {{Project.address}}', '<p>Sehr geehrte Damen und Herren,</p><p>für unser Projekt {{Project.address}} ({{Project.display_id}}) möchten wir Sie um ein Angebot für die nachstehend beschriebenen Leistungen ersuchen.</p><p>Über eine kurze Rückmeldung zu Verfügbarkeit und Konditionen freuen wir uns.</p><p>Liebe Grüße,<br>{{User.name}}<br>{{Company.name}} · {{Company.phone}}</p>', null, 90, 0, true, null, '2026-06-14 13:11:21.097264+00'::timestamptz, '2026-06-16 16:08:42.822296+00'::timestamptz, (select id from public.organizations order by created_at asc limit 1), null, null, null, 'subunternehmer_anfragen', 'subunternehmer', false)
